import http from "../01_axios"
import {
  apiGetListRank,
  apiGetRankById,
  apiInsertRank,
  apiUpdateRank,
  apiDeleteRank,
} from "./urls"

const getListRank = params => http.get(apiGetListRank, { params })
const getRankById = params => http.get(apiGetRankById, { params })
const insertRank = body => http.post(apiInsertRank, body)
const updateRank = body => http.post(apiUpdateRank, body)
const deleteRank = params => http.delete(apiDeleteRank, { params })

const MembershipPackageService = {
  getListRank,
  getRankById,
  insertRank,
  updateRank,
  deleteRank,
}
export default MembershipPackageService
